import "core-js/modules/es.array.push.js";
import "core-js/modules/es.iterator.constructor.js";
import "core-js/modules/es.iterator.find.js";
import "core-js/modules/es.iterator.for-each.js";
import "core-js/modules/es.iterator.map.js";
import prestashopService from '../services/prestashopService';
import quoteService from '../services/quoteService';
import rentalConfigService from '../services/rentalConfigService';
import quoteSettingsService from '../services/quoteSettingsService';
import customerService from '../services/customerService';
import Icon from '../components/Icons.vue';
export default {
  name: 'EditQuote',
  components: {
    CustomIcon
  },
  props: {
    quoteId: {
      type: String,
      required: true
    }
  },
  data() {
    return {
      formData: {
        quote_type: 'standard',
        customer_name: '',
        customer_email: '',
        customer_phone: ''
      },
      searchQuery: '',
      searchResults: [],
      searching: false,
      selectedProducts: [],
      rentalConfigs: [],
      quoteSettings: null,
      customerSuggestions: [],
      emailInputFocused: false,
      searchTimeout: null,
      emailSearchTimeout: null,
      error: null
    };
  },
  async mounted() {
    await this.loadRentalConfigs();
    await this.loadQuoteSettings();
    await this.loadQuoteData();
  },
  methods: {
    async loadRentalConfigs() {
      try {
        this.rentalConfigs = await rentalConfigService.getAll();
        console.log('Configurations de location chargées:', this.rentalConfigs);
      } catch (err) {
        console.error('Erreur lors du chargement des configurations:', err);
      }
    },
    async loadQuoteSettings() {
      try {
        this.quoteSettings = await quoteSettingsService.get();
      } catch (err) {
        console.error('Erreur lors du chargement des paramètres de devis:', err);
      }
    },
    async loadQuoteData() {
      try {
        const {
          data: quote,
          error: quoteError
        } = await supabase.from('quotes').select('*').eq('id', this.quoteId).maybeSingle();
        if (quoteError) throw quoteError;
        if (!quote) {
          this.error = 'Devis introuvable';
          return;
        }
        this.formData = {
          quote_type: quote.quote_type || 'standard',
          customer_name: quote.customer_name || '',
          customer_email: quote.customer_email || '',
          customer_phone: quote.customer_phone || ''
        };
        const {
          data: items,
          error: itemsError
        } = await supabase.from('quote_items').select('*').eq('quote_id', this.quoteId);
        if (itemsError) throw itemsError;
        this.selectedProducts = (items || []).map(item => ({
          product_id: item.product_id,
          product_reference: item.product_reference || '',
          product_name: item.product_name,
          price: parseFloat(item.price) || 0,
          original_price: item.original_price ? parseFloat(item.original_price) : null,
          discount_percentage: item.discount_percentage ? parseFloat(item.discount_percentage) : null,
          is_rental: item.is_rental || false,
          duration_months: item.duration_months,
          rate_percentage: item.rate_percentage ? parseFloat(item.rate_percentage) : null,
          rental_config_id: item.rental_config_id
        }));
      } catch (err) {
        this.error = 'Erreur lors du chargement du devis: ' + err.message;
        console.error(err);
      }
    },
    calculateValidUntil() {
      if (!this.quoteSettings || !this.quoteSettings.validity_hours) {
        return '-';
      }
      const date = new Date();
      date.setHours(date.getHours() + this.quoteSettings.validity_hours);
      return date.toLocaleDateString('fr-FR', {
        year: 'numeric',
        month: 'long',
        day: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
      });
    },
    onSearchInput() {
      clearTimeout(this.searchTimeout);
      if (this.searchQuery.length < 2) {
        this.searchResults = [];
        return;
      }
      this.searchTimeout = setTimeout(() => {
        this.searchProducts();
      }, 500);
    },
    async searchProducts() {
      if (!this.searchQuery || this.searchQuery.length < 2) {
        return;
      }
      try {
        this.searching = true;
        this.error = null;
        this.searchResults = await prestashopService.searchProducts(this.searchQuery);
      } catch (err) {
        this.error = 'Erreur lors de la recherche: ' + err.message;
        console.error(err);
        this.searchResults = [];
      } finally {
        this.searching = false;
      }
    },
    addProduct(product) {
      const alreadyAdded = this.selectedProducts.find(p => p.product_id === product.id);
      if (alreadyAdded) {
        this.error = 'Ce produit est déjà dans la liste';
        setTimeout(() => {
          this.error = null;
        }, 3000);
        return;
      }
      const isRentalOnly = this.formData.quote_type === 'rental_only';
      this.selectedProducts.push({
        product_id: product.id,
        product_reference: product.reference || '',
        product_name: product.name,
        price: parseFloat(product.price) || 0,
        original_price: product.originalPrice ? parseFloat(product.originalPrice) : null,
        discount_percentage: product.discountPercentage ? parseFloat(product.discountPercentage) : null,
        is_rental: isRentalOnly,
        duration_months: null,
        rate_percentage: null,
        rental_config_id: null
      });
      this.searchQuery = '';
      this.searchResults = [];
    },
    removeProduct(index) {
      this.selectedProducts.splice(index, 1);
    },
    onQuoteTypeChange() {
      if (this.formData.quote_type === 'rental_only') {
        this.selectedProducts.forEach(item => {
          item.is_rental = true;
        });
      } else {
        this.selectedProducts.forEach(item => {
          item.is_rental = false;
          item.duration_months = null;
          item.rate_percentage = null;
        });
      }
    },
    async onEmailInput() {
      clearTimeout(this.emailSearchTimeout);
      if (this.formData.customer_email.length < 3) {
        this.customerSuggestions = [];
        return;
      }
      this.emailSearchTimeout = setTimeout(async () => {
        try {
          this.customerSuggestions = await customerService.search(this.formData.customer_email);
        } catch (err) {
          console.error('Erreur recherche clients:', err);
        }
      }, 500);
    },
    selectCustomer(customer) {
      this.formData.customer_email = customer.email;
      this.formData.customer_name = customer.name || '';
      this.formData.customer_phone = customer.phone || '';
      this.customerSuggestions = [];
      this.emailInputFocused = false;
    },
    onEmailBlur() {
      setTimeout(() => {
        this.emailInputFocused = false;
      }, 200);
    },
    onRentalChange(item) {
      if (!item.is_rental) {
        item.duration_months = null;
        item.rate_percentage = null;
        item.rental_config_id = null;
      } else if (item.duration_months) {
        this.calculateRate(item);
      }
    },
    calculateRate(item) {
      console.log('calculateRate appelé:', {
        is_rental: item.is_rental,
        duration_months: item.duration_months,
        price: item.price,
        configs: this.rentalConfigs
      });
      if (!item.is_rental || !item.duration_months || !item.price) {
        item.rate_percentage = null;
        return;
      }
      const config = this.rentalConfigs.find(c => item.price >= c.price_min && item.price <= c.price_max);
      console.log('Configuration trouvée:', config);
      if (config) {
        item.rental_config_id = config.id;
        const rate = item.duration_months === 36 ? config.duration_36_months : config.duration_60_months;
        console.log('Taux calculé:', rate);
        this.$set(item, 'rate_percentage', parseFloat(rate));
      } else {
        item.rental_config_id = null;
        item.rate_percentage = null;
        this.error = `Aucune configuration de location trouvée pour le prix ${this.formatPrice(item.price)}`;
        setTimeout(() => {
          this.error = null;
        }, 3000);
      }
    },
    async saveQuote() {
      if (!this.formData.customer_name) {
        this.error = 'Veuillez saisir le nom du client';
        return;
      }
      if (this.selectedProducts.length === 0) {
        this.error = 'Veuillez ajouter au moins un produit';
        return;
      }
      for (const product of this.selectedProducts) {
        if (product.is_rental && (!product.duration_months || !product.rate_percentage)) {
          this.error = 'Veuillez configurer tous les produits en location';
          return;
        }
      }
      try {
        const quoteData = {
          quote_type: this.formData.quote_type,
          customer_name: this.formData.customer_name,
          customer_email: this.formData.customer_email || null,
          customer_phone: this.formData.customer_phone || null,
          updated_at: new Date().toISOString()
        };
        await quoteService.update(this.quoteId, quoteData);
        const {
          error: deleteError
        } = await supabase.from('quote_items').delete().eq('quote_id', this.quoteId);
        if (deleteError) throw deleteError;
        const itemsToInsert = this.selectedProducts.map(item => ({
          quote_id: this.quoteId,
          product_id: item.product_id,
          product_reference: item.product_reference,
          product_name: item.product_name,
          price: item.price,
          original_price: item.original_price,
          discount_percentage: item.discount_percentage,
          is_rental: item.is_rental || false,
          duration_months: item.duration_months,
          rate_percentage: item.rate_percentage,
          rental_config_id: item.rental_config_id
        }));
        const {
          error: insertError
        } = await supabase.from('quote_items').insert(itemsToInsert);
        if (insertError) throw insertError;
        this.goBack();
      } catch (err) {
        this.error = 'Erreur lors de la modification du devis: ' + err.message;
        console.error(err);
      }
    },
    calculateMonthlyPayment(item) {
      if (!item.price || !item.duration_months || !item.rate_percentage) {
        return 0;
      }
      const principal = item.price;
      const monthlyRate = item.rate_percentage / 100 / 12;
      const numberOfPayments = item.duration_months;
      const monthlyPayment = principal * (monthlyRate * Math.pow(1 + monthlyRate, numberOfPayments)) / (Math.pow(1 + monthlyRate, numberOfPayments) - 1);
      return monthlyPayment;
    },
    formatPrice(price) {
      return new Intl.NumberFormat('fr-FR', {
        style: 'currency',
        currency: 'EUR'
      }).format(price);
    },
    goBack() {
      this.$emit('navigate', 'quotes-list');
    }
  }
};
